import './styles/globals.css';
import './styles/toast.css';
import './features/theme/theme.css';
import { GameShell } from 'host-kit';
import { EngineSlot } from './slots/EngineSlot.js';
import { GridSlot } from './slots/GridSlot.js';
import { PadSlot } from './slots/PadSlot.js';
import { ToolbarSlot } from './slots/ToolbarSlot.js';
import { StatsSlot } from './slots/StatsSlot.js';
import { HintsSlot } from './slots/HintsSlot.js';
import { ThemeSlot } from './slots/ThemeSlot.js';
import { GameLayout } from './features/layout/index.js';
import { usePuzzleSolvedSubscriber, useToastStore } from './features/achievements/achievements.js';

const SUDOKU_THEME = {
  heroGradient: 'linear-gradient(180deg, #f2f2f7 0%, #ffffff 100%)',
  glowColor: '#007aff',
  accentText: '#1c1c1e',
  accentTextLight: '#48484a',
};

function AchievementSubscriber() {
  usePuzzleSolvedSubscriber();
  return null;
}

function ToastContainer() {
  const toasts = useToastStore((s) => s.toasts);
  if (toasts.length === 0) return null;
  return (
    <div className="sk-toast-container" aria-live="polite">
      {toasts.map((t) => (
        <div key={t.id} className="sk-toast">{t.message}</div>
      ))}
    </div>
  );
}

export default function App() {
  return (
    <div className="sudoku-app-root">
      <GameShell eyebrow="Bilko · Game" title="Sudoku" tagline="A clean, calm, free Sudoku." theme={SUDOKU_THEME}>
        <AchievementSubscriber />
        <GameLayout
          topBarRight={<ThemeSlot />}
          playArea={
            <EngineSlot>
              <StatsSlot />
              <HintsSlot />
              <GridSlot />
            </EngineSlot>
          }
          bottomBar={
            <>
              <PadSlot />
              <ToolbarSlot />
            </>
          }
        />
        <ToastContainer />
      </GameShell>
    </div>
  );
}
