import type { Board, ValidationResult } from './index.js';
import { ROW_UNITS, COL_UNITS, BOX_UNITS } from './peers.js';

export function validate(b: Board): ValidationResult {
  const conflicts = new Set<number>();

  function checkUnit(unit: readonly number[]): void {
    // seen[digit] = first cell index where that digit was seen
    const seen = new Array<number>(10).fill(-1);
    for (const idx of unit) {
      const v = b.cells[idx]!;
      if (v === 0) continue;
      const prev = seen[v]!;
      if (prev !== -1) {
        conflicts.add(idx);
        conflicts.add(prev);
      } else {
        seen[v] = idx;
      }
    }
  }

  for (const unit of ROW_UNITS) checkUnit(unit);
  for (const unit of COL_UNITS) checkUnit(unit);
  for (const unit of BOX_UNITS) checkUnit(unit);

  const sorted = [...conflicts].sort((a, b) => a - b);
  return { ok: sorted.length === 0, conflicts: sorted };
}

export function isSolved(b: Board): boolean {
  for (let i = 0; i < 81; i++) {
    if (b.cells[i] === 0) return false;
  }
  return validate(b).ok;
}
