/**
 * Human solving techniques — pure functions that analyse candidates and return
 * the first applicable deduction without modifying the board.
 *
 * Return type: null (technique doesn't apply) or TechResult describing what to
 * place/eliminate so callers (solver, hint engine) can act on it.
 */

import type { Board, Digit, CellIdx, Technique } from './index.js';
import {
  ROW_UNITS, COL_UNITS, BOX_UNITS, ALL_UNITS,
  PEERS, BOX_OF, ROW_OF, COL_OF,
  CELLS_IN_BOX_ROW, CELLS_IN_BOX_COL,
} from './peers.js';
import { setCell, setCandidate } from './board.js';

export interface TechResult {
  technique: Technique;
  /** Cells that are the focus of this deduction (for hint rendering). */
  focusCells: CellIdx[];
  /** If a digit is placed, the target cell and digit. */
  placement?: { idx: CellIdx; digit: Digit };
  /** Candidate eliminations: remove `digit` from `cells`. */
  eliminations: Array<{ idx: CellIdx; digit: Digit }>;
}

// bit utilities
export function popcount(n: number): number {
  n = n - ((n >> 1) & 0x55555555);
  n = (n & 0x33333333) + ((n >> 2) & 0x33333333);
  return (((n + (n >> 4)) & 0x0f0f0f0f) * 0x01010101) >>> 24;
}

/** Lowest set bit position (1..9). Precondition: n > 0. */
export function lsb(n: number): number {
  return 31 - Math.clz32(n & -n);
}

/** Iterate set bit positions (1..9) in a candidate bitmask. */
export function* bitsOf(mask: number): Generator<number> {
  let m = mask;
  while (m) {
    const b = m & -m;
    yield 31 - Math.clz32(b);
    m ^= b;
  }
}

// ── Naked Single ────────────────────────────────────────────────────────────
// A cell with exactly one candidate.

export function nakedSingle(b: Board): TechResult | null {
  for (let i = 0; i < 81; i++) {
    if (b.cells[i] !== 0) continue;
    const c = b.candidates[i]!;
    if (popcount(c) === 1) {
      const d = lsb(c) as Digit;
      return {
        technique: 'naked-single',
        focusCells: [i],
        placement: { idx: i, digit: d },
        eliminations: [],
      };
    }
  }
  return null;
}

// ── Hidden Single ────────────────────────────────────────────────────────────
// In a unit, exactly one cell can hold a given digit.

export function hiddenSingle(b: Board): TechResult | null {
  for (const unit of ALL_UNITS) {
    for (let d = 1; d <= 9; d++) {
      const mask = 1 << d;
      let count = 0;
      let last = -1;
      for (const idx of unit) {
        if (b.cells[idx] !== 0) continue;
        if (b.candidates[idx]! & mask) { count++; last = idx; }
        if (count > 1) break;
      }
      if (count === 1) {
        return {
          technique: 'hidden-single',
          focusCells: [...unit],
          placement: { idx: last, digit: d as Digit },
          eliminations: [],
        };
      }
    }
  }
  return null;
}

// ── Naked Pair ───────────────────────────────────────────────────────────────
// Two cells in the same unit share exactly the same 2 candidates.

export function nakedPair(b: Board): TechResult | null {
  for (const unit of ALL_UNITS) {
    const twos = unit.filter(i => b.cells[i] === 0 && popcount(b.candidates[i]!) === 2);
    for (let a = 0; a < twos.length; a++) {
      for (let bb = a + 1; bb < twos.length; bb++) {
        const ca = b.candidates[twos[a]!]!;
        const cb = b.candidates[twos[bb]!]!;
        if (ca !== cb) continue;
        const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
        for (const idx of unit) {
          if (idx === twos[a] || idx === twos[bb]!) continue;
          if (b.cells[idx] !== 0) continue;
          for (const d of bitsOf(ca & b.candidates[idx]!)) {
            elim.push({ idx, digit: d as Digit });
          }
        }
        if (elim.length === 0) continue;
        return {
          technique: 'naked-pair',
          focusCells: [twos[a]!, twos[bb]!],
          eliminations: elim,
        };
      }
    }
  }
  return null;
}

// ── Hidden Pair ──────────────────────────────────────────────────────────────
// Two digits appear as candidates in exactly two cells of a unit.

export function hiddenPair(b: Board): TechResult | null {
  for (const unit of ALL_UNITS) {
    const empty = unit.filter(i => b.cells[i] === 0);
    // for each pair of digits, find how many cells can hold each
    for (let d1 = 1; d1 <= 8; d1++) {
      for (let d2 = d1 + 1; d2 <= 9; d2++) {
        const m1 = 1 << d1, m2 = 1 << d2;
        const cells1 = empty.filter(i => b.candidates[i]! & m1);
        const cells2 = empty.filter(i => b.candidates[i]! & m2);
        if (cells1.length !== 2 || cells2.length !== 2) continue;
        if (cells1[0] !== cells2[0] || cells1[1] !== cells2[1]) continue;
        const [c0, c1] = cells1 as [number, number];
        const pairMask = m1 | m2;
        const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
        for (const idx of [c0, c1]) {
          for (const d of bitsOf(b.candidates[idx]! & ~pairMask)) {
            elim.push({ idx, digit: d as Digit });
          }
        }
        if (elim.length === 0) continue;
        return {
          technique: 'hidden-pair',
          focusCells: [c0, c1],
          eliminations: elim,
        };
      }
    }
  }
  return null;
}

// ── Pointing Pair/Triple ──────────────────────────────────────────────────────
// Within a box, if a digit appears only in one row (or column), it can be
// eliminated from the rest of that row (or column) outside the box.

export function pointingPair(b: Board): TechResult | null {
  for (let box = 0; box < 9; box++) {
    const boxCells = BOX_UNITS[box]!;

    // Check rows
    for (let d = 1; d <= 9; d++) {
      const dm = 1 << d;
      const rows = CELLS_IN_BOX_ROW[box]!;
      for (let ri = 0; ri < 3; ri++) {
        const rowLine = rows[ri]!;
        const inRow = rowLine.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm));
        if (inRow.length === 0) continue;
        const allInBox = boxCells.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm));
        if (allInBox.length !== inRow.length) continue;
        // All candidates for d in this box lie in this row → eliminate from row outside box
        const globalRow = ROW_OF[inRow[0]!]!;
        const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
        for (const idx of ROW_UNITS[globalRow]!) {
          if (boxCells.includes(idx)) continue;
          if (b.cells[idx] !== 0) continue;
          if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
        }
        if (elim.length === 0) continue;
        return { technique: 'pointing-pair', focusCells: inRow, eliminations: elim };
      }

      // Check cols
      const cols = CELLS_IN_BOX_COL[box]!;
      for (let ci = 0; ci < 3; ci++) {
        const colLine = cols[ci]!;
        const inCol = colLine.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm));
        if (inCol.length === 0) continue;
        const allInBox = boxCells.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm));
        if (allInBox.length !== inCol.length) continue;
        const globalCol = COL_OF[inCol[0]!]!;
        const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
        for (const idx of COL_UNITS[globalCol]!) {
          if (boxCells.includes(idx)) continue;
          if (b.cells[idx] !== 0) continue;
          if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
        }
        if (elim.length === 0) continue;
        return { technique: 'pointing-pair', focusCells: inCol, eliminations: elim };
      }
    }
  }
  return null;
}

// ── Box/Line Reduction ────────────────────────────────────────────────────────
// In a row/col, if a digit appears only within one box, it can be eliminated
// from the rest of that box.

export function boxLineReduction(b: Board): TechResult | null {
  for (let d = 1; d <= 9; d++) {
    const dm = 1 << d;

    // By row
    for (let r = 0; r < 9; r++) {
      const cands = ROW_UNITS[r]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm));
      if (cands.length === 0) continue;
      const boxSet = new Set(cands.map(i => BOX_OF[i]!));
      if (boxSet.size !== 1) continue;
      const box = [...boxSet][0]!;
      const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
      for (const idx of BOX_UNITS[box]!) {
        if (ROW_OF[idx] === r) continue;
        if (b.cells[idx] !== 0) continue;
        if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
      }
      if (elim.length === 0) continue;
      return { technique: 'box-line-reduction', focusCells: cands, eliminations: elim };
    }

    // By col
    for (let c = 0; c < 9; c++) {
      const cands = COL_UNITS[c]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm));
      if (cands.length === 0) continue;
      const boxSet = new Set(cands.map(i => BOX_OF[i]!));
      if (boxSet.size !== 1) continue;
      const box = [...boxSet][0]!;
      const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
      for (const idx of BOX_UNITS[box]!) {
        if (COL_OF[idx] === c) continue;
        if (b.cells[idx] !== 0) continue;
        if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
      }
      if (elim.length === 0) continue;
      return { technique: 'box-line-reduction', focusCells: cands, eliminations: elim };
    }
  }
  return null;
}

// ── X-Wing ────────────────────────────────────────────────────────────────────
// A digit appears in exactly 2 cells in each of 2 rows, in the same columns.
// Eliminate from those columns elsewhere.

export function xWing(b: Board): TechResult | null {
  for (let d = 1; d <= 9; d++) {
    const dm = 1 << d;

    // Row-based
    const rowPairs: Array<{ r: number; cols: number[] }> = [];
    for (let r = 0; r < 9; r++) {
      const cols = ROW_UNITS[r]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm))
        .map(i => COL_OF[i]!);
      if (cols.length === 2) rowPairs.push({ r, cols });
    }
    for (let a = 0; a < rowPairs.length; a++) {
      for (let bb = a + 1; bb < rowPairs.length; bb++) {
        const pa = rowPairs[a]!, pb = rowPairs[bb]!;
        if (pa.cols[0] !== pb.cols[0] || pa.cols[1] !== pb.cols[1]) continue;
        const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
        for (const c of pa.cols) {
          for (const idx of COL_UNITS[c]!) {
            const rr = ROW_OF[idx]!;
            if (rr === pa.r || rr === pb.r) continue;
            if (b.cells[idx] !== 0) continue;
            if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
          }
        }
        if (elim.length === 0) continue;
        const focusCells = [
          ...ROW_UNITS[pa.r]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm)),
          ...ROW_UNITS[pb.r]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm)),
        ];
        return { technique: 'x-wing', focusCells, eliminations: elim };
      }
    }

    // Col-based
    const colPairs: Array<{ c: number; rows: number[] }> = [];
    for (let c = 0; c < 9; c++) {
      const rows = COL_UNITS[c]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm))
        .map(i => ROW_OF[i]!);
      if (rows.length === 2) colPairs.push({ c, rows });
    }
    for (let a = 0; a < colPairs.length; a++) {
      for (let bb = a + 1; bb < colPairs.length; bb++) {
        const pa = colPairs[a]!, pb = colPairs[bb]!;
        if (pa.rows[0] !== pb.rows[0] || pa.rows[1] !== pb.rows[1]) continue;
        const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
        for (const r of pa.rows) {
          for (const idx of ROW_UNITS[r]!) {
            const cc = COL_OF[idx]!;
            if (cc === pa.c || cc === pb.c) continue;
            if (b.cells[idx] !== 0) continue;
            if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
          }
        }
        if (elim.length === 0) continue;
        const focusCells = [
          ...COL_UNITS[pa.c]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm)),
          ...COL_UNITS[pb.c]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm)),
        ];
        return { technique: 'x-wing', focusCells, eliminations: elim };
      }
    }
  }
  return null;
}

// ── Swordfish ─────────────────────────────────────────────────────────────────
// Like X-Wing but with 3 rows/cols (digit appears in ≤2 positions per row, all
// in the same 3 columns).

export function swordfish(b: Board): TechResult | null {
  for (let d = 1; d <= 9; d++) {
    const dm = 1 << d;

    // Row-based
    const rowData: Array<{ r: number; cols: number[] }> = [];
    for (let r = 0; r < 9; r++) {
      const cols = ROW_UNITS[r]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm))
        .map(i => COL_OF[i]!);
      if (cols.length >= 2 && cols.length <= 3) rowData.push({ r, cols });
    }
    for (let a = 0; a < rowData.length; a++) {
      for (let bb = a + 1; bb < rowData.length; bb++) {
        for (let cc = bb + 1; cc < rowData.length; cc++) {
          const ra = rowData[a]!, rb = rowData[bb]!, rc = rowData[cc]!;
          const colSet = new Set([...ra.cols, ...rb.cols, ...rc.cols]);
          if (colSet.size !== 3) continue;
          const cols = [...colSet];
          const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
          for (const c of cols) {
            for (const idx of COL_UNITS[c]!) {
              const rr = ROW_OF[idx]!;
              if (rr === ra.r || rr === rb.r || rr === rc.r) continue;
              if (b.cells[idx] !== 0) continue;
              if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
            }
          }
          if (elim.length === 0) continue;
          const focusCells = [ra.r, rb.r, rc.r].flatMap(r =>
            ROW_UNITS[r]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm)),
          );
          return { technique: 'swordfish', focusCells, eliminations: elim };
        }
      }
    }

    // Col-based (symmetric)
    const colData: Array<{ c: number; rows: number[] }> = [];
    for (let c = 0; c < 9; c++) {
      const rows = COL_UNITS[c]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm))
        .map(i => ROW_OF[i]!);
      if (rows.length >= 2 && rows.length <= 3) colData.push({ c, rows });
    }
    for (let a = 0; a < colData.length; a++) {
      for (let bb = a + 1; bb < colData.length; bb++) {
        for (let cc = bb + 1; cc < colData.length; cc++) {
          const ca = colData[a]!, cb = colData[bb]!, ccol = colData[cc]!;
          const rowSet = new Set([...ca.rows, ...cb.rows, ...ccol.rows]);
          if (rowSet.size !== 3) continue;
          const rows = [...rowSet];
          const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
          for (const r of rows) {
            for (const idx of ROW_UNITS[r]!) {
              const col = COL_OF[idx]!;
              if (col === ca.c || col === cb.c || col === ccol.c) continue;
              if (b.cells[idx] !== 0) continue;
              if (b.candidates[idx]! & dm) elim.push({ idx, digit: d as Digit });
            }
          }
          if (elim.length === 0) continue;
          const focusCells = [ca.c, cb.c, ccol.c].flatMap(c =>
            COL_UNITS[c]!.filter(i => b.cells[i] === 0 && (b.candidates[i]! & dm)),
          );
          return { technique: 'swordfish', focusCells, eliminations: elim };
        }
      }
    }
  }
  return null;
}

// ── XY-Wing ───────────────────────────────────────────────────────────────────
// Pivot cell A has exactly 2 candidates {x,y}. Pincers B (shares unit with A,
// has {x,z}) and C (shares unit with A, has {y,z}). Any cell that sees both B
// and C cannot contain z.

export function xyWing(b: Board): TechResult | null {
  const bivalue = Array.from({ length: 81 }, (_, i) => i)
    .filter(i => b.cells[i] === 0 && popcount(b.candidates[i]!) === 2);

  for (const pivot of bivalue) {
    const [x, y] = [...bitsOf(b.candidates[pivot]!)] as [number, number];
    const pivotPeers = PEERS[pivot]!.filter(i => b.cells[i] === 0);

    // Find pincers that share a unit with pivot
    const pincerB = pivotPeers.filter(i => {
      const c = b.candidates[i]!;
      return popcount(c) === 2 && (c & (1 << x)) && !(c & (1 << y));
    });
    const pincerC = pivotPeers.filter(i => {
      const c = b.candidates[i]!;
      return popcount(c) === 2 && (c & (1 << y)) && !(c & (1 << x));
    });

    for (const pb of pincerB) {
      // z is the other digit in B (not x)
      const z = lsb(b.candidates[pb]! ^ (1 << x));
      // C must have candidates {y, z}
      const zm = 1 << z;
      const validC = pincerC.filter(i => b.candidates[i]! === ((1 << y) | zm));
      for (const pc of validC) {
        const elim: Array<{ idx: CellIdx; digit: Digit }> = [];
        for (const idx of PEERS[pb]!) {
          if (!PEERS[pc]!.includes(idx)) continue;
          if (idx === pivot) continue;
          if (b.cells[idx] !== 0) continue;
          if (b.candidates[idx]! & zm) elim.push({ idx, digit: z as Digit });
        }
        if (elim.length === 0) continue;
        return {
          technique: 'xy-wing',
          focusCells: [pivot, pb, pc],
          eliminations: elim,
        };
      }
    }
  }
  return null;
}

// ── Apply a TechResult to a board ─────────────────────────────────────────────

export function applyTech(b: Board, t: TechResult): Board {
  let cur = b;
  if (t.placement) {
    cur = setCell(cur, t.placement.idx, t.placement.digit);
  }
  for (const e of t.eliminations) {
    if (cur.cells[e.idx] === 0 && (cur.candidates[e.idx]! & (1 << e.digit))) {
      cur = setCandidate(cur, e.idx, e.digit, false);
    }
  }
  return cur;
}

// Ordered list of all human techniques (cheapest first)
export const HUMAN_TECHNIQUES: ReadonlyArray<(b: Board) => TechResult | null> = [
  nakedSingle,
  hiddenSingle,
  nakedPair,
  hiddenPair,
  pointingPair,
  boxLineReduction,
  xWing,
  swordfish,
  xyWing,
];

export const TECHNIQUE_RANK: Record<Technique, number> = {
  'naked-single': 0,
  'hidden-single': 1,
  'naked-pair': 2,
  'hidden-pair': 3,
  'pointing-pair': 4,
  'box-line-reduction': 5,
  'x-wing': 6,
  'swordfish': 7,
  'xy-wing': 8,
  'guess': 9,
};
