import { useStreakStore } from '../../state/streak-store.js';
import { isoDate } from './streak.js';

interface Props {
  onCopy: () => void;
}

export function ShareTile({ onCopy }: Props) {
  const streak = useStreakStore(s => s.state);
  const stats = useStreakStore(s => s.lastWinStats);

  if (!stats) return null;

  function buildText(): string {
    const { timeMs, mistakes, hintsUsed, difficulty } = stats!;
    const min = Math.floor(timeMs / 60000);
    const sec = Math.floor((timeMs % 60000) / 1000);
    const today = isoDate(new Date());
    const dateFmt = new Date().toLocaleDateString(undefined, { weekday: 'short', month: 'numeric', day: 'numeric' });
    return [
      `Bilko Sudoku · ${dateFmt} · ${difficulty}`,
      `⏱ ${min}:${String(sec).padStart(2, '0')}  ❤️ ${mistakes} mistake${mistakes !== 1 ? 's' : ''}  💡 ${hintsUsed} hint${hintsUsed !== 1 ? 's' : ''}`,
      `🔥 streak ${streak.current}`,
      `bilko.run/projects/sudoku/?d=${today}`,
    ].join('\n');
  }

  async function share() {
    const text = buildText();
    if (typeof navigator !== 'undefined' && navigator.share) {
      try { await navigator.share({ text }); return; } catch {}
    }
    await navigator.clipboard.writeText(text);
    onCopy();
  }

  return (
    <button className="share-btn" onClick={share}>
      Share
    </button>
  );
}
