/**
 * Lifetime per-difficulty stats persisted in localStorage.
 *
 * On every win we add 1 to puzzlesWon, accumulate mistakes and time, and
 * keep a running min for "best time". This is independent of the daily
 * streak store — that one tracks calendar coverage; this one tracks raw
 * volume + skill.
 *
 * Complexity: every recordWin is O(1).
 * Bundle: this file is lazy-loaded with the StatsSheet, so it costs zero
 * on first paint.
 */
import type { Difficulty } from '../../engine/index.js';

const KEY = 'bilko_sudoku_stats_v1';

export interface PerDiff {
  puzzlesWon: number;
  bestTimeMs: number | null;
  totalTimeMs: number;
  totalMistakes: number;
  totalHints: number;
  perfectWins: number; // 0 mistakes, 0 hints
}

export interface LifetimeStats {
  byDifficulty: Record<Difficulty, PerDiff>;
}

const DIFFS: Difficulty[] = ['easy', 'medium', 'hard', 'expert', 'master', 'evil'];

function emptyPer(): PerDiff {
  return { puzzlesWon: 0, bestTimeMs: null, totalTimeMs: 0, totalMistakes: 0, totalHints: 0, perfectWins: 0 };
}

function emptyStats(): LifetimeStats {
  const by = {} as Record<Difficulty, PerDiff>;
  for (const d of DIFFS) by[d] = emptyPer();
  return { byDifficulty: by };
}

export function loadStats(): LifetimeStats {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return emptyStats();
    const parsed = JSON.parse(raw);
    // Backfill any difficulty that didn't exist when the data was saved.
    const out = emptyStats();
    if (parsed?.byDifficulty) {
      for (const d of DIFFS) {
        if (parsed.byDifficulty[d]) out.byDifficulty[d] = { ...emptyPer(), ...parsed.byDifficulty[d] };
      }
    }
    return out;
  } catch {
    return emptyStats();
  }
}

export interface WinPayload {
  difficulty: Difficulty;
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
}

export function recordWin(payload: WinPayload): LifetimeStats {
  const s = loadStats();
  const cur = s.byDifficulty[payload.difficulty];
  cur.puzzlesWon += 1;
  cur.totalTimeMs += payload.timeMs;
  cur.totalMistakes += payload.mistakes;
  cur.totalHints += payload.hintsUsed;
  if (payload.mistakes === 0 && payload.hintsUsed === 0) cur.perfectWins += 1;
  if (payload.timeMs > 0 && (cur.bestTimeMs == null || payload.timeMs < cur.bestTimeMs)) {
    cur.bestTimeMs = payload.timeMs;
  }
  try { localStorage.setItem(KEY, JSON.stringify(s)); } catch {}
  return s;
}

export function formatMs(ms: number | null): string {
  if (ms == null) return '—';
  const total = Math.floor(ms / 1000);
  const m = Math.floor(total / 60);
  const s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

export const DIFFICULTIES_IN_ORDER = DIFFS;
