import type { Board, Digit, CellIdx } from './index.js';
import { PEERS } from './peers.js';

// O(n) — compute all candidate bitmasks from scratch
export function computeAllCandidates(cells: Uint8Array): Uint16Array {
  const cands = new Uint16Array(81);
  for (let i = 0; i < 81; i++) {
    if (cells[i] !== 0) continue;
    let used = 0;
    for (const p of PEERS[i]!) {
      used |= 1 << cells[p]!;
    }
    cands[i] = (~used) & 0x3fe; // bits 1-9
  }
  return cands;
}

// TypedArrays cannot be Object.freeze'd in V8; immutability is a TypeScript-level contract.
function freeze(cells: Uint8Array, givens: Uint8Array, cands: Uint16Array): Board {
  return {
    cells: cells as Readonly<Uint8Array>,
    givens: givens as Readonly<Uint8Array>,
    candidates: cands as Readonly<Uint16Array>,
  };
}

export function emptyBoard(): Board {
  const cells = new Uint8Array(81);
  const givens = new Uint8Array(81);
  // all empty → all 9 digits are candidates for every cell
  const cands = new Uint16Array(81).fill(0x3fe);
  return freeze(cells, givens, cands);
}

export function fromString(s: string): Board {
  const cells = new Uint8Array(81);
  const givens = new Uint8Array(81);
  let idx = 0;
  for (let i = 0; i < s.length && idx < 81; i++) {
    const ch = s[i]!;
    if (ch >= '1' && ch <= '9') {
      cells[idx] = parseInt(ch, 10) as Digit;
      givens[idx] = 1;
      idx++;
    } else if (ch === '0' || ch === '.') {
      idx++;
    }
  }
  return freeze(cells, givens, computeAllCandidates(cells));
}

export function toString(b: Board): string {
  let out = '';
  for (let i = 0; i < 81; i++) out += b.cells[i]!.toString();
  return out;
}

export function setCell(b: Board, idx: CellIdx, value: Digit): Board {
  const cells = b.cells.slice() as Uint8Array;
  const givens = b.givens.slice() as Uint8Array;
  const cands = b.candidates.slice() as Uint16Array;
  cells[idx] = value;
  cands[idx] = 0;
  if (value !== 0) {
    const mask = ~(1 << value);
    for (const p of PEERS[idx]!) {
      cands[p]! &= mask;
    }
  } else {
    // Clearing: recompute all candidates because restoring a digit affects peers
    return freeze(cells, givens, computeAllCandidates(cells));
  }
  return freeze(cells, givens, cands);
}

export function setCandidate(b: Board, idx: CellIdx, digit: Digit, on: boolean): Board {
  const cands = b.candidates.slice() as Uint16Array;
  if (on) {
    cands[idx]! |= 1 << digit;
  } else {
    cands[idx]! &= ~(1 << digit);
  }
  return freeze(b.cells.slice() as Uint8Array, b.givens.slice() as Uint8Array, cands);
}

export function clearCell(b: Board, idx: CellIdx): Board {
  if (b.cells[idx] === 0) return b;
  return setCell(b, idx, 0 as Digit);
}
