import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus.js';

export function LiveRegion() {
  const [msg, setMsg] = useState('');

  useEffect(() => {
    const offs = [
      bus.on('cellChanged', ({ row, col, value, isNote }) => {
        if (row < 0) return;
        setMsg(
          value
            ? `${isNote ? 'Note ' : ''}${value} ${isNote ? 'toggled' : 'placed'} at row ${row + 1} column ${col + 1}.`
            : `Cell at row ${row + 1} column ${col + 1} cleared.`
        );
      }),
      bus.on('puzzleSolved', () => setMsg('Puzzle solved. Well done.')),
    ];
    return () => offs.forEach(off => off());
  }, []);

  return (
    <div className="sr-only" role="status" aria-live="polite" aria-atomic="true">
      {msg}
    </div>
  );
}
