import { useEffect, useState, type ReactNode } from 'react';
import { useGameState } from '../../state/store.js';
import { Tutorial, hasSeenTutorial } from '../tutorial/index.js';
import { SettingsSheet, useSettings } from '../settings/index.js';
import { useStreakStore } from '../../state/streak-store.js';
import './layout.css';

/**
 * Full-bleed Sudoku layout.
 *
 *   ┌─────────────────────────────────────────────────────────────┐
 *   │  [diff] [timer]               [streak] [?] [⚙]              │  top-bar
 *   ├─────────────────────────────────────────────────────────────┤
 *   │                                                             │
 *   │                       9 × 9 board                           │  play-area
 *   │                                                             │
 *   ├─────────────────────────────────────────────────────────────┤
 *   │   1 2 3 4 5 6 7 8 9 · ⌫ ↶ ↷ 💡 ✏️                            │  bottom-bar
 *   └─────────────────────────────────────────────────────────────┘
 *
 * v0.4 adds:
 *   - Streak chip in the top-right (current daily streak; clickable to open
 *     stats sheet via the settings cog).
 *   - Settings cog that opens a full sheet rather than the old cramped
 *     popover. The popover still exists in ThemeMenu for backwards-compat
 *     with the legacy theme tests but the cog is the primary surface.
 *   - Timer can be hidden via settings.
 */

interface Props {
  playArea: ReactNode;
  bottomBar: ReactNode;
  topBarLeft?: ReactNode;
  topBarRight?: ReactNode;
}

export function GameLayout({ playArea, bottomBar, topBarLeft, topBarRight }: Props) {
  const [tutorialOpen, setTutorialOpen] = useState(false);
  const [settingsOpen, setSettingsOpen] = useState(false);

  useEffect(() => {
    if (!hasSeenTutorial()) setTutorialOpen(true);
  }, []);

  const { difficulty, timeMs } = useGameState();
  const timerVisible = useSettings((s) => s.timerVisible);
  const streak = useStreakStore((s) => s.state.current);

  return (
    <div className="game-layout">
      <div className="top-bar" role="region" aria-label="Game status">
        <div className="top-bar-left">
          <span className="diff-chip" aria-label={`Difficulty ${difficulty}`}>{difficulty}</span>
          {timerVisible && (
            <span className="timer" aria-label={`Elapsed time ${formatTime(timeMs)}`}>
              {formatTime(timeMs)}
            </span>
          )}
          {topBarLeft}
        </div>
        <div className="top-bar-right">
          {streak > 0 && (
            <button
              type="button"
              className="streak-chip"
              aria-label={`Current streak ${streak} day${streak === 1 ? '' : 's'}, open stats`}
              title={`Streak: ${streak} day${streak === 1 ? '' : 's'}`}
              onClick={() => setSettingsOpen(true)}
            >
              🔥<span>{streak}</span>
            </button>
          )}
          <button
            type="button"
            className="help-btn"
            aria-label="How to play"
            title="How to play"
            onClick={() => setTutorialOpen(true)}
          >
            ?
          </button>
          <button
            type="button"
            className="settings-btn"
            aria-label="Settings"
            title="Settings"
            onClick={() => setSettingsOpen(true)}
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" aria-hidden="true">
              <path
                d="M12 15a3 3 0 100-6 3 3 0 000 6z"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
              />
              <path
                d="M19.4 15a1.65 1.65 0 00.33 1.82l.06.06a2 2 0 11-2.83 2.83l-.06-.06a1.65 1.65 0 00-1.82-.33 1.65 1.65 0 00-1 1.51V21a2 2 0 11-4 0v-.09a1.65 1.65 0 00-1-1.51 1.65 1.65 0 00-1.82.33l-.06.06a2 2 0 11-2.83-2.83l.06-.06a1.65 1.65 0 00.33-1.82 1.65 1.65 0 00-1.51-1H3a2 2 0 110-4h.09a1.65 1.65 0 001.51-1 1.65 1.65 0 00-.33-1.82l-.06-.06a2 2 0 112.83-2.83l.06.06a1.65 1.65 0 001.82.33h.01a1.65 1.65 0 001-1.51V3a2 2 0 114 0v.09a1.65 1.65 0 001 1.51 1.65 1.65 0 001.82-.33l.06-.06a2 2 0 112.83 2.83l-.06.06a1.65 1.65 0 00-.33 1.82v.01a1.65 1.65 0 001.51 1H21a2 2 0 110 4h-.09a1.65 1.65 0 00-1.51 1z"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </button>
          {topBarRight}
        </div>
      </div>

      <div className="play-area">{playArea}</div>

      <div className="bottom-bar">{bottomBar}</div>

      <Tutorial open={tutorialOpen} onClose={() => setTutorialOpen(false)} />
      <SettingsSheet open={settingsOpen} onClose={() => setSettingsOpen(false)} />
    </div>
  );
}

/** O(1) — millis to MM:SS clock. */
function formatTime(ms: number): string {
  const total = Math.max(0, Math.floor(ms / 1000));
  const m = Math.floor(total / 60);
  const s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}
