// Precomputed geometry for a 9×9 Sudoku grid.
// All indices are row-major: idx = row * 9 + col.

export const ROW_OF = new Uint8Array(81);
export const COL_OF = new Uint8Array(81);
export const BOX_OF = new Uint8Array(81);

for (let i = 0; i < 81; i++) {
  ROW_OF[i] = Math.floor(i / 9);
  COL_OF[i] = i % 9;
  BOX_OF[i] = Math.floor(ROW_OF[i]! / 3) * 3 + Math.floor(COL_OF[i]! / 3);
}

// ROW_UNITS[r] = indices of all 9 cells in row r
export const ROW_UNITS: readonly (readonly number[])[] = Array.from({ length: 9 }, (_, r) =>
  Array.from({ length: 9 }, (_, c) => r * 9 + c),
);

// COL_UNITS[c] = indices of all 9 cells in column c
export const COL_UNITS: readonly (readonly number[])[] = Array.from({ length: 9 }, (_, c) =>
  Array.from({ length: 9 }, (_, r) => r * 9 + c),
);

// BOX_UNITS[b] = indices of all 9 cells in box b (row-major box order)
export const BOX_UNITS: readonly (readonly number[])[] = Array.from({ length: 9 }, (_, b) => {
  const br = Math.floor(b / 3) * 3;
  const bc = (b % 3) * 3;
  return Array.from({ length: 9 }, (_, k) => (br + Math.floor(k / 3)) * 9 + (bc + (k % 3)));
});

export const ALL_UNITS: readonly (readonly number[])[] = [
  ...ROW_UNITS,
  ...COL_UNITS,
  ...BOX_UNITS,
];

// PEERS[i] = sorted array of 20 cells that share a unit with cell i
export const PEERS: readonly (readonly number[])[] = Array.from({ length: 81 }, (_, i) => {
  const set = new Set<number>();
  const r = ROW_OF[i]!;
  const c = COL_OF[i]!;
  const b = BOX_OF[i]!;
  for (const idx of ROW_UNITS[r]!) set.add(idx);
  for (const idx of COL_UNITS[c]!) set.add(idx);
  for (const idx of BOX_UNITS[b]!) set.add(idx);
  set.delete(i);
  return [...set].sort((a, b) => a - b);
});

// CELLS_IN_ROW_OF_BOX[b][r] = cells in box b that are also in row r (0..2 offset within box)
// Used for pointing pairs / box-line reduction
export const CELLS_IN_BOX_ROW: readonly (readonly (readonly number[])[])[] =
  Array.from({ length: 9 }, (_, b) => {
    const br = Math.floor(b / 3) * 3;
    const bc = (b % 3) * 3;
    return Array.from({ length: 3 }, (_, dr) =>
      Array.from({ length: 3 }, (_, dc) => (br + dr) * 9 + (bc + dc)),
    );
  });

export const CELLS_IN_BOX_COL: readonly (readonly (readonly number[])[])[] =
  Array.from({ length: 9 }, (_, b) => {
    const br = Math.floor(b / 3) * 3;
    const bc = (b % 3) * 3;
    return Array.from({ length: 3 }, (_, dc) =>
      Array.from({ length: 3 }, (_, dr) => (br + dr) * 9 + (bc + dc)),
    );
  });
