import type { Difficulty } from '../engine/index.js';
import { bus } from '../lib/bus.js';
import { useStore } from './store.js';
import { useStreakStore } from './streak-store.js';
import { isoDate } from '../features/daily/streak.js';

export function initBusBridge() {
  bus.on('cellChanged', ({ row, col, value, isNote }) => {
    useStore.getState().actions.placeAt(row, col, value, isNote);
  });
  bus.on('cellSelected', ({ row, col }) => {
    useStore.getState().actions.selectCell(row, col);
  });
  bus.on('modeChanged', ({ noteMode }) => {
    useStore.getState().actions.setNoteMode(noteMode);
  });
  bus.on('undoRequested', () => useStore.getState().actions.undo());
  bus.on('redoRequested', () => useStore.getState().actions.redo());
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  bus.on('newGame', ({ difficulty }) => {
    useStore.getState().actions.newGame(difficulty as Difficulty);
    // Bus-initiated new games (EngineSlot buttons) are not dailies
    useStreakStore.getState().setCurrentDailyDate(null);
  });
  bus.on('digitPrimed', ({ digit }) => useStore.setState({ primedDigit: digit }));
  bus.on('hintRequested', () => useStore.getState().actions.escalateHint());

  bus.on('puzzleSolved', ({ difficulty, timeMs, mistakes, hintsUsed }) => {
    const { currentDailyIso, recordWin } = useStreakStore.getState();
    const today = isoDate(new Date());
    if (currentDailyIso === today) {
      recordWin(today, {
        timeMs,
        mistakes,
        hintsUsed,
        difficulty: difficulty as Difficulty,
      });
    }
  });
}
