import type { Board, Digit, SolveResult, Technique } from './index.js';
import { setCell } from './board.js';
import { isSolved } from './validate.js';
import { popcount, bitsOf, HUMAN_TECHNIQUES, applyTech, TECHNIQUE_RANK } from './techniques.js';

export { TECHNIQUE_RANK };

export const TECHNIQUES: Technique[] = [
  'naked-single', 'hidden-single', 'naked-pair', 'hidden-pair',
  'pointing-pair', 'box-line-reduction', 'x-wing', 'swordfish', 'xy-wing', 'guess',
];

function zeroCounts(): Record<Technique, number> {
  return Object.fromEntries(TECHNIQUES.map(t => [t, 0])) as Record<Technique, number>;
}

/**
 * Constraint propagation: apply all human techniques repeatedly until no
 * progress, then return the reduced board (or null on contradiction).
 * O(81 * techniques) per pass, typically 1-3 passes.
 */
function propagate(b: Board, counts: Record<Technique, number>): Board | null {
  let cur = b;
  let changed = true;
  while (changed) {
    changed = false;
    // Check for contradiction first
    for (let i = 0; i < 81; i++) {
      if (cur.cells[i] === 0 && cur.candidates[i] === 0) return null;
    }
    for (const fn of HUMAN_TECHNIQUES) {
      const result = fn(cur);
      if (!result) continue;
      counts[result.technique]++;
      cur = applyTech(cur, result);
      changed = true;
      break; // restart scan with the cheapest technique first
    }
  }
  return cur;
}

/** Pick the empty cell with fewest candidates (MRV). Returns -1 if none. */
function pickCell(b: Board): number {
  let best = -1;
  let bestCount = 10;
  for (let i = 0; i < 81; i++) {
    if (b.cells[i] !== 0) continue;
    const c = popcount(b.candidates[i]!);
    if (c === 0) return -1; // contradiction signal (caller must handle)
    if (c < bestCount) { bestCount = c; best = i; }
  }
  return best;
}

export function solve(
  b: Board,
  opts: { earlyExitOnAmbiguity?: boolean } = {},
): SolveResult {
  const counts = zeroCounts();
  const found: Board[] = [];

  function recurse(cur: Board): void {
    if (found.length >= 2) return;

    const propagated = propagate(cur, counts);
    if (!propagated) return; // contradiction

    if (isSolved(propagated)) {
      found.push(propagated);
      return;
    }

    const idx = pickCell(propagated);
    if (idx < 0) return; // contradiction (zero candidates)

    for (const d of bitsOf(propagated.candidates[idx]!)) {
      counts.guess++;
      recurse(setCell(propagated, idx, d as Digit));
      if (opts.earlyExitOnAmbiguity && found.length >= 2) return;
    }
  }

  recurse(b);

  if (found.length === 0) return { ok: false, uniqueSolution: false };
  return {
    ok: true,
    board: found[0]!,
    uniqueSolution: found.length === 1,
    techniquesUsed: counts,
  };
}

/**
 * Human-technique-only solver: no backtracking guesses.
 * Returns the highest-rank technique required, or null if puzzle is fully
 * solvable without guessing.
 */
export interface HumanSolveResult {
  solved: boolean;
  techniquesUsed: Set<Technique>;
  highestRank: number; // TECHNIQUE_RANK value; -1 if no technique applied
  board: Board;
}

export function humanSolve(b: Board): HumanSolveResult {
  let cur = b;
  const used = new Set<Technique>();
  let highestRank = -1;

  let changed = true;
  while (changed) {
    changed = false;
    for (let i = 0; i < 81; i++) {
      if (cur.cells[i] === 0 && cur.candidates[i] === 0) {
        return { solved: false, techniquesUsed: used, highestRank, board: cur };
      }
    }
    for (const fn of HUMAN_TECHNIQUES) {
      const result = fn(cur);
      if (!result) continue;
      used.add(result.technique);
      const rank = TECHNIQUE_RANK[result.technique];
      if (rank > highestRank) highestRank = rank;
      cur = applyTech(cur, result);
      changed = true;
      break;
    }
  }

  return { solved: isSolved(cur), techniquesUsed: used, highestRank, board: cur };
}
