import { useEffect } from 'react';
import { TECHNIQUE_NAMES, TECHNIQUE_DESCRIPTIONS } from './techniques.js';

interface Props {
  initial: string;
  onClose: () => void;
}

export function GlossaryModal({ initial, onClose }: Props) {
  useEffect(() => {
    document.getElementById(`tech-${initial}`)?.scrollIntoView({ behavior: 'smooth' });
  }, [initial]);

  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') onClose();
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  return (
    <div
      className="glossary-backdrop"
      onClick={onClose}
      role="dialog"
      aria-modal="true"
      aria-label="Technique glossary"
    >
      <div className="glossary-sheet" onClick={e => e.stopPropagation()}>
        <header>
          <h2>Techniques</h2>
          <button onClick={onClose} aria-label="Close glossary">×</button>
        </header>
        <ul>
          {Object.keys(TECHNIQUE_NAMES).map(k => (
            <li key={k} id={`tech-${k}`} className={k === initial ? 'highlighted' : ''}>
              <h3>{TECHNIQUE_NAMES[k]}</h3>
              <p>{TECHNIQUE_DESCRIPTIONS[k]}</p>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
