import type { Board } from '../../engine/index.js';

export interface UnitCompletionEvent {
  kind: 'row' | 'col' | 'box';
  index: number;
  triggeringCell: number;
}

export function unitCellIndices(kind: 'row' | 'col' | 'box', index: number): number[] {
  if (kind === 'row') return Array.from({ length: 9 }, (_, i) => index * 9 + i);
  if (kind === 'col') return Array.from({ length: 9 }, (_, i) => i * 9 + index);
  const r0 = Math.floor(index / 3) * 3, c0 = (index % 3) * 3;
  const out: number[] = [];
  for (let r = r0; r < r0 + 3; r++) for (let c = c0; c < c0 + 3; c++) out.push(r * 9 + c);
  return out;
}

export function unitsCompletedAfterPlacement(prev: Board, next: Board, idx: number): UnitCompletionEvent[] {
  const events: UnitCompletionEvent[] = [];
  const row = Math.floor(idx / 9);
  const col = idx % 9;
  const box = Math.floor(row / 3) * 3 + Math.floor(col / 3);

  function full(cells: Readonly<Uint8Array>, indices: number[]) {
    return indices.every(i => cells[i] !== 0);
  }
  function wasIncomplete(cells: Readonly<Uint8Array>, indices: number[]) {
    return indices.some(i => cells[i] === 0);
  }

  const rowIdx = unitCellIndices('row', row);
  const colIdx = unitCellIndices('col', col);
  const boxIdx = unitCellIndices('box', box);

  if (wasIncomplete(prev.cells, rowIdx) && full(next.cells, rowIdx))
    events.push({ kind: 'row', index: row, triggeringCell: idx });
  if (wasIncomplete(prev.cells, colIdx) && full(next.cells, colIdx))
    events.push({ kind: 'col', index: col, triggeringCell: idx });
  if (wasIncomplete(prev.cells, boxIdx) && full(next.cells, boxIdx))
    events.push({ kind: 'box', index: box, triggeringCell: idx });

  return events;
}
