import type { Difficulty } from '../../engine/index.js';

export interface StreakState {
  current: number;
  longest: number;
  freezes: number;
  lastWinDate: string | null; // 'YYYY-MM-DD'
  completed: string[];        // sorted ISO dates
}

export interface CalendarDay {
  date: string;
  completed: boolean;
  difficulty: Difficulty;
  isToday: boolean;
  isOutOfRange: boolean; // padding days before the 90-day window
}

export interface WinStats {
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
  difficulty: Difficulty;
}

// Index is getUTCDay(): 0=Sun 1=Mon 2=Tue 3=Wed 4=Thu 5=Fri 6=Sat
export const DAY_DIFFICULTY: Difficulty[] = [
  'master', 'easy', 'medium', 'medium', 'hard', 'hard', 'expert',
];

export const DIFF_INITIAL: Record<Difficulty, string> = {
  easy:   'E',
  medium: 'M',
  hard:   'H',
  expert: 'X',
  master: '★',
  evil:   '!',
};

export function difficultyFor(date: Date): Difficulty {
  return DAY_DIFFICULTY[date.getUTCDay()]!;
}

export function isoDate(d: Date): string {
  return d.toISOString().slice(0, 10);
}

export function daysBetween(a: string, b: string): number {
  return Math.round((Date.parse(b) - Date.parse(a)) / 86_400_000);
}

export function applyWin(state: StreakState, date: string): StreakState {
  if (state.completed.includes(date)) return state;
  const completed = [...state.completed, date].sort();
  let current = state.current;
  let freezes = state.freezes;

  if (state.lastWinDate) {
    const gap = daysBetween(state.lastWinDate, date);
    if (gap === 1) {
      current += 1;
    } else if (gap > 1) {
      const missed = gap - 1;
      const freezesUsed = Math.min(missed, freezes);
      freezes -= freezesUsed;
      if (freezesUsed >= missed) current += 1;
      else current = 1; // streak broken; new streak starts
    }
  } else {
    current = 1;
  }

  if (completed.length % 7 === 0 && freezes < 3) freezes += 1;

  return {
    current,
    longest: Math.max(state.longest, current),
    freezes,
    lastWinDate: date,
    completed,
  };
}

export function buildCalendarDays(today: Date, completed: string[]): CalendarDay[] {
  const todayIso = isoDate(today);
  const windowStart = new Date(Date.UTC(
    today.getUTCFullYear(),
    today.getUTCMonth(),
    today.getUTCDate() - 89,
  ));
  const windowStartIso = isoDate(windowStart);

  // Pad to Monday of windowStart's week (getUTCDay: 0=Sun → offset 6, 1=Mon → offset 0)
  const dow = (windowStart.getUTCDay() + 6) % 7;
  const cur = new Date(windowStart.getTime() - dow * 86_400_000);

  const days: CalendarDay[] = [];
  while (isoDate(cur) <= todayIso) {
    const iso = isoDate(cur);
    const isOutOfRange = iso < windowStartIso;
    days.push({
      date: iso,
      completed: !isOutOfRange && completed.includes(iso),
      difficulty: difficultyFor(cur),
      isToday: iso === todayIso,
      isOutOfRange,
    });
    cur.setUTCDate(cur.getUTCDate() + 1);
  }
  return days;
}
