/**
 * Centralised user preferences for Bilko-Sudoku v0.4.
 *
 * Each setting is mirrored to `localStorage` so it persists across reloads
 * and survives a hard refresh. Values are exposed through a Zustand store
 * so any React component that subscribes (toolbar, board, settings sheet)
 * re-renders the instant the user toggles a preference.
 *
 * Persistence keys are kept stable so users who already have v0.3 settings
 * (`bilko_sudoku_theme_v1`, `bilko_sudoku_cb_v1`, etc.) don't lose them.
 *
 * Complexity: every read/write is O(1) — a single localStorage round-trip
 * plus a constant-cost Zustand `set`. No setting ever touches the board
 * arrays.
 */
import { create } from 'zustand';

export type ThemeChoice = 'light' | 'dark' | 'sepia' | 'hc' | 'system';

const K = {
  theme: 'bilko_sudoku_theme_v1',
  cb: 'bilko_sudoku_cb_v1',
  sound: 'bilko_sudoku_sounds_v1',
  haptics: 'bilko_sudoku_haptics_v1',
  conflictHl: 'bilko_sudoku_conflict_hl_v1',
  autoNotes: 'bilko_sudoku_auto_notes_v1',
  timer: 'bilko_sudoku_timer_v1',
  digitGlow: 'bilko_sudoku_digit_glow_v1',
} as const;

interface SettingsState {
  theme: ThemeChoice;
  colorBlind: boolean;
  sounds: boolean;
  haptics: boolean;
  conflictHighlight: boolean;
  autoNotes: boolean;
  timerVisible: boolean;
  digitGlow: boolean;
}

interface SettingsActions {
  setTheme: (t: ThemeChoice) => void;
  toggleColorBlind: () => void;
  setSounds: (on: boolean) => void;
  setHaptics: (on: boolean) => void;
  setConflictHighlight: (on: boolean) => void;
  setAutoNotes: (on: boolean) => void;
  setTimerVisible: (on: boolean) => void;
  setDigitGlow: (on: boolean) => void;
  resetStats: () => void;
}

function readBool(k: string, dflt: boolean): boolean {
  try {
    const v = localStorage.getItem(k);
    if (v === null) return dflt;
    return v === '1';
  } catch { return dflt; }
}

function writeBool(k: string, v: boolean): void {
  try { localStorage.setItem(k, v ? '1' : '0'); } catch {}
}

function readTheme(): ThemeChoice {
  try {
    const v = localStorage.getItem(K.theme);
    if (v === 'light' || v === 'dark' || v === 'sepia' || v === 'hc') return v;
  } catch {}
  return 'system';
}

function applyTheme(t: ThemeChoice): void {
  if (t === 'system') {
    delete document.documentElement.dataset.theme;
  } else {
    document.documentElement.dataset.theme = t;
  }
}

function applyColorBlind(on: boolean): void {
  if (on) document.documentElement.dataset.cb = '1';
  else delete document.documentElement.dataset.cb;
}

export const useSettings = create<SettingsState & { actions: SettingsActions }>((set) => ({
  theme: readTheme(),
  colorBlind: readBool(K.cb, false),
  sounds: readBool(K.sound, false),                  // mute-by-default
  haptics: readBool(K.haptics, true),                // on by default; cheap, easy to ignore
  conflictHighlight: readBool(K.conflictHl, true),
  autoNotes: readBool(K.autoNotes, true),
  timerVisible: readBool(K.timer, true),
  digitGlow: readBool(K.digitGlow, true),

  actions: {
    setTheme: (t) => {
      if (t === 'system') { try { localStorage.removeItem(K.theme); } catch {} }
      else { try { localStorage.setItem(K.theme, t); } catch {} }
      applyTheme(t);
      set({ theme: t });
    },
    toggleColorBlind: () => set((s) => {
      const next = !s.colorBlind;
      writeBool(K.cb, next);
      applyColorBlind(next);
      return { colorBlind: next };
    }),
    setSounds: (on) => { writeBool(K.sound, on); set({ sounds: on }); },
    setHaptics: (on) => { writeBool(K.haptics, on); set({ haptics: on }); },
    setConflictHighlight: (on) => { writeBool(K.conflictHl, on); set({ conflictHighlight: on }); },
    setAutoNotes: (on) => { writeBool(K.autoNotes, on); set({ autoNotes: on }); },
    setTimerVisible: (on) => { writeBool(K.timer, on); set({ timerVisible: on }); },
    setDigitGlow: (on) => { writeBool(K.digitGlow, on); set({ digitGlow: on }); },
    resetStats: () => {
      try {
        localStorage.removeItem('bilko_sudoku_streak_v1');
        localStorage.removeItem('bilko_sudoku_stats_v1');
      } catch {}
    },
  },
}));

/** Apply the persisted theme + cb mode synchronously on app boot. */
export function bootSettings(): void {
  applyTheme(readTheme());
  applyColorBlind(readBool(K.cb, false));
}
