import { useEffect, useState } from 'react';
import { useStreakStore } from '../../state/streak-store.js';
import { useGameActions } from '../../state/store.js';
import { difficultyFor, isoDate } from './streak.js';
import { dailySeed } from '../../engine/index.js';
import { CalendarSheet } from './CalendarSheet.js';
import { ShareTile } from './ShareTile.js';
import './daily.css';

export function DailyHero() {
  const streakState = useStreakStore(s => s.state);
  const setCurrentDailyDate = useStreakStore(s => s.setCurrentDailyDate);
  const lastWinStats = useStreakStore(s => s.lastWinStats);
  const actions = useGameActions();
  const [showCal, setShowCal] = useState(false);
  const [copied, setCopied] = useState(false);

  const today = new Date();
  const todayIso = isoDate(today);
  const completed = streakState.completed.includes(todayIso);
  const dayName = today.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
  const diff = difficultyFor(today);

  function playToday() {
    setCurrentDailyDate(todayIso);
    actions.newGame(diff, dailySeed(today), todayIso);
  }

  // Auto-load from URL param ?d=YYYY-MM-DD
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const d = params.get('d');
    if (d && /^\d{4}-\d{2}-\d{2}$/.test(d)) {
      const date = new Date(d + 'T12:00:00Z');
      const isToday = d === todayIso;
      if (isToday) {
        setCurrentDailyDate(todayIso);
        actions.newGame(difficultyFor(date), dailySeed(date), todayIso);
      } else {
        setCurrentDailyDate(null);
        actions.newGame(difficultyFor(date), dailySeed(date));
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="daily-hero">
      <div className="daily-hero-body">
        <p className="eyebrow">Daily · {dayName}</p>
        <h2 className="daily-diff">{diff}</h2>
        {completed ? (
          <div className="daily-done">
            <p className="muted">Solved · streak {streakState.current} 🔥</p>
            {lastWinStats && (
              <ShareTile onCopy={() => { setCopied(true); setTimeout(() => setCopied(false), 2000); }} />
            )}
            {copied && <span className="copied-notice">Copied!</span>}
          </div>
        ) : (
          <button className="play-btn" onClick={playToday}>Play today</button>
        )}
      </div>
      <button className="cal-btn" onClick={() => setShowCal(true)} aria-label="Open calendar">📅</button>
      {showCal && <CalendarSheet onClose={() => setShowCal(false)} />}
    </div>
  );
}
