function useUnlocks(game) {
  const [unlocks, setUnlocks] = useState([]);
  const [achievements, setAchievements] = useState([]);
  const [lastCrossUnlock, setLastCrossUnlock] = useState(null);
  useEffect(() => {
    void (async () => {
      const [u, a] = await Promise.all([
        fetch(`${HOST2}/api/games/${game}/unlocks`, { credentials: "include" }).then((r) => r.ok ? r.json() : { unlocks: [] }),
        fetch(`${HOST2}/api/games/${game}/achievements`).then((r) => r.ok ? r.json() : { achievements: [] })
      ]);
      setUnlocks(u.unlocks ?? []);
      setAchievements(a.achievements ?? []);
    })();
  }, [game]);
  const unlock = useCallback(async (key) => {
    const r = await fetch(`${HOST2}/api/games/${game}/unlock`, {
      method: "POST",
      credentials: "include",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ key })
    });
    if (r.ok) {
      const j = await r.json();
      setUnlocks(
        (prev) => prev.some((u) => u.key === key) ? prev : [...prev, { key, unlocked_at: j.unlocked_at }]
      );
      if (j.crossUnlock) setLastCrossUnlock(j.crossUnlock);
      return true;
    }
    return false;
  }, [game]);
  return { unlocks, achievements, unlock, lastCrossUnlock };
}

