import { useRef } from 'react';
import type { Board } from '../../engine/index.js';
import { bus } from '../../lib/bus.js';
import { haptics } from '../../features/feedback/haptics.js';
import './pad.css';

interface Props {
  board: Board;
  selection: { row: number; col: number } | null;
  noteMode: boolean;
  primedDigit: number | null;
}

// O(81) — iterate all cells once per digit button press
function countDigit(board: Board, d: number): number {
  let n = 0;
  for (let i = 0; i < 81; i++) if (board.cells[i] === d) n++;
  return n;
}

interface PadButtonProps {
  d: number;
  exhausted: boolean;
  active: boolean;
  noteMode: boolean;
  count: number;
  onPress: () => void;
}

function PadButton({ d, exhausted, active, noteMode, count, onPress }: PadButtonProps) {
  const startedAt = useRef<number>(0);
  const longPressed = useRef(false);

  function handlePointerDown() {
    startedAt.current = Date.now();
    longPressed.current = false;
    setTimeout(() => {
      if (Date.now() - startedAt.current >= 220) {
        longPressed.current = true;
        haptics.tick();
        bus.emit('modeChanged', { noteMode: true });
        const off = bus.on('cellChanged', () => {
          bus.emit('modeChanged', { noteMode: false });
          off();
        });
      }
    }, 220);
  }

  function handlePointerUp() {
    if (longPressed.current) { longPressed.current = false; return; }
    onPress();
  }

  return (
    <button
      className={`pad-btn${exhausted ? ' exhausted' : ''}${active ? ' active' : ''}`}
      data-exhausted={exhausted || undefined}
      data-active={active || undefined}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      aria-label={`Number ${d}${exhausted ? ' (all placed)' : `, ${count} of 9 placed`}${noteMode ? ', note mode' : ''}`}
    >
      <span className="digit">{d}</span>
      <span className="pip">{exhausted ? '✓' : `${count}/9`}</span>
      {noteMode && <span className="note-badge">N</span>}
    </button>
  );
}

export function NumberPad({ board, selection, noteMode, primedDigit }: Props) {
  function press(d: number) {
    const count = countDigit(board, d);
    if (count >= 9) return;
    if (selection && selection.row >= 0) {
      bus.emit('cellChanged', { row: selection.row, col: selection.col, value: d, isNote: noteMode });
    } else {
      bus.emit('digitPrimed', { digit: d });
    }
  }

  return (
    <div className="number-pad" role="toolbar" aria-label="Number pad">
      {([1, 2, 3, 4, 5, 6, 7, 8, 9] as const).map(d => {
        const count = countDigit(board, d);
        return (
          <PadButton
            key={d}
            d={d}
            exhausted={count >= 9}
            active={primedDigit === d}
            noteMode={noteMode}
            count={count}
            onPress={() => press(d)}
          />
        );
      })}
    </div>
  );
}
