import { useEffect, useRef, useState, lazy, Suspense } from 'react';
import { useSettings, type ThemeChoice } from './settings.js';
import './settings.css';

/* ─────────────────────────────────────────────────────────────────────────
 * SettingsSheet — single source of truth for every user-tweakable option.
 *
 * Layout: bottom-sheet on mobile (thumb-reachable), centered modal on tablet+.
 *
 * Keyboard:
 *   - Esc closes
 *   - Tab cycles inside the sheet (native order is enough — first focusable
 *     is the close button, last is "Reset stats")
 *   - Theme swatches respond to Enter / Space
 *
 * Stats are lazy-loaded so a user who never opens settings never pays for
 * the stats screen.
 * ───────────────────────────────────────────────────────────────────────── */

const StatsSheetLazy = lazy(() =>
  import('../stats/StatsSheet.js').then((m) => ({ default: m.StatsSheet })),
);

const THEME_PREVIEW: Record<Exclude<ThemeChoice, 'system'>, { paper: string; entered: string }> = {
  light: { paper: '#ffffff', entered: '#007aff' },
  dark:  { paper: '#1c1c1e', entered: '#0a84ff' },
  sepia: { paper: '#f6ecd2', entered: '#8a4a00' },
  hc:    { paper: '#ffffff', entered: '#0033cc' },
};

const THEME_LIST: { id: ThemeChoice; label: string }[] = [
  { id: 'light',  label: 'Light' },
  { id: 'dark',   label: 'Dark' },
  { id: 'sepia',  label: 'Sepia' },
  { id: 'hc',     label: 'Contrast' },
  { id: 'system', label: 'System' },
];

interface Props { open: boolean; onClose: () => void }

export function SettingsSheet({ open, onClose }: Props) {
  const settings = useSettings();
  const a = settings.actions;
  const [statsOpen, setStatsOpen] = useState(false);
  const sheetRef = useRef<HTMLDivElement>(null);
  const firstFocusableRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    if (!open) return;
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') { e.preventDefault(); onClose(); }
    }
    document.addEventListener('keydown', onKey);
    // Focus the close button on open so Tab walks through the sheet, not the
    // background grid.
    setTimeout(() => firstFocusableRef.current?.focus(), 50);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose]);

  if (!open) return null;

  return (
    <>
      <div
        className="settings-backdrop"
        role="dialog"
        aria-modal="true"
        aria-label="Settings"
        onClick={onClose}
      >
        <div
          ref={sheetRef}
          className="settings-sheet"
          onClick={(e) => e.stopPropagation()}
          style={{ position: 'relative' }}
        >
          <button
            ref={firstFocusableRef}
            className="sheet-close"
            aria-label="Close settings"
            onClick={onClose}
          >×</button>
          <h2>Settings</h2>

          <h3>Theme</h3>
          <div className="theme-swatches" role="radiogroup" aria-label="Theme">
            {THEME_LIST.map(({ id, label }) => {
              const prev = id === 'system'
                ? { paper: '#888', entered: '#444' }
                : THEME_PREVIEW[id];
              const active = settings.theme === id;
              return (
                <button
                  key={id}
                  type="button"
                  role="radio"
                  aria-checked={active}
                  aria-label={label}
                  data-active={active || undefined}
                  className="theme-swatch"
                  onClick={() => a.setTheme(id)}
                  style={{
                    ['--sw-paper' as string]: prev.paper,
                    ['--sw-entered' as string]: prev.entered,
                  }}
                >
                  <span className="swatch-chip" aria-hidden="true" />
                  <span className="swatch-name">{label}</span>
                </button>
              );
            })}
          </div>

          <h3>Display</h3>
          <SettingToggle
            label="Color-blind safe colors"
            hint="Amber instead of red, deeper blue"
            checked={settings.colorBlind}
            onChange={a.toggleColorBlind}
          />
          <SettingToggle
            label="Show timer"
            hint="Hide the clock for relaxed solving"
            checked={settings.timerVisible}
            onChange={(v) => a.setTimerVisible(v)}
          />
          <SettingToggle
            label="Highlight conflicts"
            hint="Pulse + shake when a digit conflicts"
            checked={settings.conflictHighlight}
            onChange={(v) => a.setConflictHighlight(v)}
          />
          <SettingToggle
            label="Glow matching digits"
            hint="Selecting a digit lights up its peers"
            checked={settings.digitGlow}
            onChange={(v) => a.setDigitGlow(v)}
          />
          <SettingToggle
            label="Auto-notes"
            hint="Fill pencil marks based on peers"
            checked={settings.autoNotes}
            onChange={(v) => a.setAutoNotes(v)}
          />

          <h3>Feedback</h3>
          <SettingToggle
            label="Sounds"
            hint="Subtle synthesized tones"
            checked={settings.sounds}
            onChange={(v) => a.setSounds(v)}
          />
          <SettingToggle
            label="Haptics"
            hint="Tiny vibration on supported devices"
            checked={settings.haptics}
            onChange={(v) => a.setHaptics(v)}
          />

          <h3>Data</h3>
          <div className="settings-row" style={{ flexDirection: 'column', alignItems: 'stretch' }}>
            <button
              type="button"
              className="open-stats"
              onClick={() => setStatsOpen(true)}
            >
              View personal stats
            </button>
            <button
              type="button"
              className="danger-btn"
              onClick={() => {
                if (confirm('Reset all streak + stats data? This cannot be undone.')) {
                  a.resetStats();
                  location.reload();
                }
              }}
            >
              Reset stats &amp; streak
            </button>
          </div>
        </div>
      </div>
      {statsOpen && (
        <Suspense fallback={null}>
          <StatsSheetLazy onClose={() => setStatsOpen(false)} />
        </Suspense>
      )}
    </>
  );
}

interface ToggleProps {
  label: string;
  hint?: string;
  checked: boolean;
  onChange: (v: boolean) => void;
}

function SettingToggle({ label, hint, checked, onChange }: ToggleProps) {
  return (
    <div className="settings-row">
      <label>
        {label}
        {hint && <span className="row-hint">{hint}</span>}
      </label>
      <span className="toggle">
        <input
          type="checkbox"
          aria-label={label}
          checked={checked}
          onChange={(e) => onChange(e.target.checked)}
        />
        <span className="track" />
        <span className="thumb" />
      </span>
    </div>
  );
}
