import { useEffect, useReducer, useRef, useState } from 'react';
import { useSettings, type ThemeChoice } from '../settings/index.js';
import './theme.css';

/**
 * Backwards-compat popover from v0.3. We keep this surface so the original
 * test suite + the floating-button affordance still work. The settings sheet
 * is the primary UI in v0.4 — both write to the same persistence keys via
 * the centralized `useSettings` store.
 *
 * The popover only exposes the legacy three-option theme list (light, dark,
 * system) plus the colour-blind / haptics / sounds toggles. The full theme
 * palette (sepia, hc) plus the new toggles live in the settings sheet.
 */
const LEGACY_CHOICES: ThemeChoice[] = ['light', 'dark', 'system'];

export function ThemeMenu() {
  const [open, setOpen] = useState(false);
  const theme = useSettings((s) => s.theme);
  const cb = useSettings((s) => s.colorBlind);
  const sounds = useSettings((s) => s.sounds);
  const haptics = useSettings((s) => s.haptics);
  const a = useSettings((s) => s.actions);
  const [, forceUpdate] = useReducer((x: number) => x + 1, 0);
  const btnRef = useRef<HTMLButtonElement>(null);
  const popoverRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function offClick(e: MouseEvent) {
      if (
        popoverRef.current && !popoverRef.current.contains(e.target as Node) &&
        btnRef.current && !btnRef.current.contains(e.target as Node)
      ) setOpen(false);
    }
    function onEscape(e: KeyboardEvent) {
      if (e.key === 'Escape') { setOpen(false); btnRef.current?.focus(); }
    }
    if (open) {
      document.addEventListener('mousedown', offClick);
      document.addEventListener('keydown', onEscape);
    }
    return () => {
      document.removeEventListener('mousedown', offClick);
      document.removeEventListener('keydown', onEscape);
    };
  }, [open]);

  return (
    <div className="theme-menu">
      <button
        ref={btnRef}
        onClick={() => setOpen((o) => !o)}
        aria-label="Theme settings"
        aria-expanded={open}
        aria-haspopup="true"
        className="theme-btn"
      >
        Aa
      </button>
      {open && (
        <div ref={popoverRef} className="theme-popover">
          <fieldset>
            <legend>Theme</legend>
            {LEGACY_CHOICES.map((c) => (
              <label key={c}>
                <input
                  type="radio"
                  name="theme"
                  value={c}
                  checked={c === theme}
                  onChange={() => a.setTheme(c)}
                />
                {c.charAt(0).toUpperCase() + c.slice(1)}
              </label>
            ))}
          </fieldset>
          <hr />
          <label>
            <input type="checkbox" checked={cb} onChange={a.toggleColorBlind} />
            Color-blind safe
          </label>
          <label>
            <input
              type="checkbox"
              checked={haptics}
              onChange={(e) => { a.setHaptics(e.target.checked); forceUpdate(); }}
            />
            Haptics
          </label>
          <label>
            <input
              type="checkbox"
              checked={sounds}
              onChange={(e) => { a.setSounds(e.target.checked); forceUpdate(); }}
            />
            Sounds
          </label>
        </div>
      )}
    </div>
  );
}
