import type { Board } from '../../engine/index.js';
import { Notes } from './Notes.js';

interface Props {
  idx: number;
  row: number;
  col: number;
  board: Board;
  isSelected: boolean;
  isPeer: boolean;
  isSameDigit: boolean;
  isConflict: boolean;
  isHintHighlight?: boolean;
  /** Show all geometrically viable candidates (peer-pruned) in empty cells. */
  autoNotes?: boolean;
  onClick: () => void;
}

export function Cell({
  idx, row, col, board,
  isSelected, isPeer, isSameDigit, isConflict, isHintHighlight,
  autoNotes = true,
  onClick,
}: Props) {
  const value = board.cells[idx] ?? 0;
  const isGiven = board.givens[idx] === 1;
  const cands = board.candidates[idx] ?? 0;

  // `cands` is the peer-pruned viable set maintained by board.setCell.
  // When autoNotes is off, an empty cell renders blank — the player can
  // still long-press to add their own notes via setCandidate.
  const noteDigits =
    value === 0 && autoNotes
      ? ([1, 2, 3, 4, 5, 6, 7, 8, 9] as const).filter((d) => (cands & (1 << d)) !== 0)
      : [];

  const stateClass = isSelected
    ? 'selected'
    : isPeer
    ? 'peer'
    : isSameDigit
    ? 'same-digit'
    : isHintHighlight
    ? 'hint-highlight'
    : '';

  return (
    <div
      role="gridcell"
      data-row={row}
      data-col={col}
      data-cell-idx={idx}
      data-selected={isSelected ? '' : undefined}
      data-given={isGiven ? '' : undefined}
      data-conflict={isConflict ? '' : undefined}
      onClick={onClick}
      className={`sudoku-cell${stateClass ? ` ${stateClass}` : ''}`}
      tabIndex={isSelected ? 0 : -1}
      aria-label={`Cell ${row + 1},${col + 1}${value ? `: ${value}` : ': empty'}${isGiven ? ' (given)' : ''}`}
      aria-selected={isSelected}
    >
      {value > 0 ? (
        <span className={`digit ${isGiven ? 'given' : 'entered'}`}>{value}</span>
      ) : noteDigits.length > 0 ? (
        <Notes digits={noteDigits} />
      ) : null}
    </div>
  );
}
