/**
 * Sound design — synthesized at runtime via Web Audio, no asset weight.
 *
 * Mute by default. The first user-gesture-induced sound call boots the
 * AudioContext lazily and reuses it for the lifetime of the page. Sounds
 * are short, low-volume sine waves so they sit under the room without
 * fatiguing the player.
 *
 *  place  → 440 Hz, 30 ms      (digit committed)
 *  note   → 660 Hz, 20 ms      (pencil-mark toggled)
 *  eraser → 220 Hz, 40 ms      (cell cleared)
 *  hint   → 720 Hz, 110 ms     (hint reveal — bell tone)
 *  error  → 180 Hz sawtooth    (conflict placed)
 *  win    → C-E-G major chord  (puzzle solved)
 *
 * All tones obey reduced-motion only insofar as they're optional; users
 * who care about silence can toggle "Sounds" off in settings.
 *
 * Complexity: every call is O(1) — one oscillator + gain node, both
 * garbage-collected when stopped.
 */
const KEY = 'bilko_sudoku_sounds_v1';
let ctx: AudioContext | null = null;
let _testFactory: (() => AudioContext) | null = null;

function enabled(): boolean { return localStorage.getItem(KEY) === '1'; }

function getCtx(): AudioContext | null {
  if (!enabled()) return null;
  if (ctx) return ctx;
  try {
    if (_testFactory) { ctx = _testFactory(); return ctx; }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const g = globalThis as any;
    const AC: typeof AudioContext | undefined = g.AudioContext ?? g.webkitAudioContext;
    if (!AC) return null;
    ctx = new AC();
    return ctx;
  } catch {
    return null;
  }
}

export function _injectAudioContextFactory(factory: (() => AudioContext) | null): void {
  _testFactory = factory;
}

interface ToneSpec {
  freq: number;
  durMs: number;
  type?: OscillatorType;
  vol?: number;
}

function tone(spec: ToneSpec): void {
  const c = getCtx();
  if (!c) return;
  const osc = c.createOscillator();
  const gain = c.createGain();
  osc.type = spec.type ?? 'sine';
  osc.frequency.value = spec.freq;
  gain.gain.value = spec.vol ?? 0.04;
  // Exponential fade-out smooths the "click" you'd otherwise hear when an
  // oscillator stops mid-cycle. Guarded so test mocks without AudioParam
  // automation methods still pass through.
  if (typeof gain.gain.setValueAtTime === 'function' &&
      typeof gain.gain.exponentialRampToValueAtTime === 'function') {
    gain.gain.setValueAtTime(spec.vol ?? 0.04, c.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, c.currentTime + spec.durMs / 1000);
  }
  osc.connect(gain);
  gain.connect(c.destination);
  osc.start();
  osc.stop(c.currentTime + spec.durMs / 1000);
}

function chord(freqs: number[], totalMs: number): void {
  const stepMs = totalMs / freqs.length;
  freqs.forEach((f, i) => setTimeout(() => tone({ freq: f, durMs: stepMs }), i * stepMs));
}

export const sound = {
  place:  () => tone({ freq: 440, durMs: 30 }),
  note:   () => tone({ freq: 660, durMs: 20 }),
  eraser: () => tone({ freq: 220, durMs: 40 }),
  hint:   () => tone({ freq: 720, durMs: 110, vol: 0.05 }),
  error:  () => tone({ freq: 180, durMs: 120, type: 'sawtooth', vol: 0.05 }),
  win:    () => chord([523.25, 659.25, 783.99], 540),
};

export function setSoundsEnabled(on: boolean): void {
  localStorage.setItem(KEY, on ? '1' : '0');
  if (!on && ctx) { ctx.close(); ctx = null; }
}
export function isSoundsEnabled(): boolean { return enabled(); }

export function _getCtxForTest(): AudioContext | null { return ctx; }
