import { useStreakStore } from '../../state/streak-store.js';
import { useGameActions } from '../../state/store.js';
import { difficultyFor, isoDate, buildCalendarDays, DIFF_INITIAL } from './streak.js';
import { dailySeed } from '../../engine/index.js';

const DAY_HEADERS = ['Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa', 'Su'];

interface Props {
  onClose: () => void;
}

export function CalendarSheet({ onClose }: Props) {
  const completed = useStreakStore(s => s.state.completed);
  const setCurrentDailyDate = useStreakStore(s => s.setCurrentDailyDate);
  const actions = useGameActions();

  const today = new Date();
  const todayIso = isoDate(today);
  const days = buildCalendarDays(today, completed);

  function loadDay(dateIso: string) {
    const date = new Date(dateIso + 'T12:00:00Z');
    setCurrentDailyDate(null); // replays don't affect streak
    actions.newGame(difficultyFor(date), dailySeed(date));
    onClose();
  }

  return (
    <div className="cal-backdrop" onClick={onClose} role="dialog" aria-modal aria-label="Daily calendar">
      <div className="cal-sheet" onClick={e => e.stopPropagation()}>
        <div className="cal-header">
          <span>Past 90 Days</span>
          <button className="cal-close" onClick={onClose} aria-label="Close">✕</button>
        </div>

        <div className="cal-grid">
          {DAY_HEADERS.map(h => (
            <div key={h} className="cal-day-header">{h}</div>
          ))}
          {days.map(day => {
            const isDisabled = day.isOutOfRange || day.date > todayIso;
            return (
              <button
                key={day.date}
                className={[
                  'cal-cell',
                  day.isOutOfRange ? 'out-of-range' : '',
                  day.isToday ? 'today' : '',
                  day.completed ? 'done' : '',
                  isDisabled ? 'disabled' : '',
                ].filter(Boolean).join(' ')}
                onClick={() => !isDisabled && loadDay(day.date)}
                disabled={isDisabled}
                aria-label={`${day.date}${day.completed ? ' – completed' : ''}`}
              >
                <span className="cal-num">{new Date(day.date + 'T12:00:00Z').getUTCDate()}</span>
                {!day.isOutOfRange && (
                  <span className="cal-diff">{DIFF_INITIAL[day.difficulty]}</span>
                )}
                {day.completed && <span className="cal-check" aria-hidden>✓</span>}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}
