import { createBus } from 'host-kit';
import type { SudokuEvents } from './events.js';

// Intersection with Record<string, unknown> satisfies createBus's index-signature constraint
// while preserving specific payload types for each event key.
export const bus = createBus<SudokuEvents & Record<string, unknown>>();

if (typeof window !== 'undefined') {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  (window as any).__sudoku_bus = bus;
}
