import { useEffect, useRef, useState } from 'react';

/* Notes — pencil-mark sub-grid (3×3 of digits).
 *
 * Pencil-mark elegance (v0.4): when a digit is dropped from a cell (because a
 * peer placement just pruned it) we briefly render it with a cross-out class
 * before unmounting. The fade-out runs entirely in CSS (`@keyframes
 * note-strike`) so the animation costs no JS once it's queued.
 *
 * Diffing strategy: keep last-render's digit list in a ref; on each render
 * compute the symmetric difference and stage any "going away" digits for
 * ~180 ms before actually dropping them. */
const FADE_MS = 180;

export function Notes({ digits }: { digits: number[] }) {
  const prevRef = useRef<number[]>(digits);
  const [striking, setStriking] = useState<number[]>([]);

  useEffect(() => {
    const removed = prevRef.current.filter((d) => !digits.includes(d));
    if (removed.length > 0) {
      setStriking((s) => [...new Set([...s, ...removed])]);
      const t = setTimeout(() => {
        setStriking((s) => s.filter((d) => !removed.includes(d)));
      }, FADE_MS);
      prevRef.current = digits;
      return () => clearTimeout(t);
    }
    prevRef.current = digits;
    return undefined;
  }, [digits]);

  return (
    <div className="sudoku-notes" aria-hidden="true">
      {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((d) => {
        const on = digits.includes(d);
        const fading = !on && striking.includes(d);
        let cls = '';
        if (on) cls = 'on';
        else if (fading) cls = 'striking';
        else cls = 'off';
        return (
          <span key={d} className={cls}>
            {on || fading ? d : ''}
          </span>
        );
      })}
    </div>
  );
}
