import { useEffect, useState, lazy, Suspense, type ReactNode } from 'react';
import { useStore, useGameState, useGameActions } from '../state/store.js';
import { bus } from '../lib/bus.js';
import { Confetti } from '../features/anim/Confetti.js';
import { CloudSaveBridge } from '../state/cloud-save.js';
import { recordWin } from '../features/stats/stats-store.js';
import { useStreakStore } from '../state/streak-store.js';
import type { Difficulty } from '../engine/index.js';
import type { WinPayload } from '../features/win/WinModal.js';

// WinModal is shown at most once per session; lazy-loading keeps it out of
// the critical path. The chunk lands ~3-4 KB gzipped.
const WinModalLazy = lazy(() =>
  import('../features/win/WinModal.js').then((m) => ({ default: m.WinModal })),
);

export function EngineSlot({ children }: { children: ReactNode }) {
  // 1-second timer tick, pauses when game is paused or solved
  useEffect(() => {
    const id = setInterval(() => {
      const s = useStore.getState();
      if (s.paused || s.solved) return;
      useStore.setState({ timeMs: s.timeMs + 1000 });
    }, 1000);
    return () => clearInterval(id);
  }, []);

  // Pause on tab visibility change
  useEffect(() => {
    function onVisibility() {
      useStore.getState().actions.pause(document.visibilityState === 'hidden');
    }
    document.addEventListener('visibilitychange', onVisibility);
    return () => document.removeEventListener('visibilitychange', onVisibility);
  }, []);

  const [confettiOn, setConfettiOn] = useState(false);
  const [winPayload, setWinPayload] = useState<WinPayload | null>(null);

  useEffect(() => {
    return bus.on('puzzleSolved', (p) => {
      setConfettiOn(true);
      // Capture lifetime stats. Streak is bumped in the bus-bridge separately.
      const updated = recordWin({
        difficulty: p.difficulty as Difficulty,
        timeMs: p.timeMs,
        mistakes: p.mistakes,
        hintsUsed: p.hintsUsed,
      });
      void updated;
      const streak = useStreakStore.getState().state.current;
      setWinPayload({
        difficulty: String(p.difficulty),
        timeMs: p.timeMs,
        mistakes: p.mistakes,
        hintsUsed: p.hintsUsed,
        streak,
      });
    });
  }, []);

  const s = useGameState();
  const actions = useGameActions();
  const isEmpty = s.board.cells.every(c => c === 0);

  return (
    <>
      {confettiOn && <Confetti onDone={() => setConfettiOn(false)} />}
      {winPayload && (
        <Suspense fallback={null}>
          <WinModalLazy
            win={winPayload}
            onClose={() => setWinPayload(null)}
            onNewGame={() => actions.newGame(s.difficulty)}
          />
        </Suspense>
      )}
      <div data-slot="engine" className="flex flex-col gap-4">
        <CloudSaveBridge />
        {!s.solved && isEmpty && (
          <div className="new-game-bar flex gap-2 justify-center py-2">
            <button onClick={() => actions.newGame('easy')}>New Easy</button>
            <button onClick={() => actions.newGame('medium')}>New Medium</button>
            <button onClick={() => actions.newGame('hard')}>New Hard</button>
            <button onClick={() => actions.newGame('expert')}>New Expert</button>
          </div>
        )}
        {children}
      </div>
    </>
  );
}
